+/*
+ * @test id=FORK
+ * @summary Check that we don't accumulate leaked FDs in the parent process
+ * @requires os.family == "linux"
+ * @library /test/lib
+ * @run main/othervm -Djdk.lang.Process.launchMechanism=fork NonPipelineLeaksFD
